import type { TailwindConfig } from "react-email";

import { defaultTheme } from "@/components/email/theme-default";
import {
  BlogContent,
  BlogEmailShell,
} from "@/components/email/blog-shared";

export interface PodcastBlogSplitProps {
  theme?: TailwindConfig;
  episode?: string;
  excerpt?: string;
  host?: string;
  imageAlt?: string;
  imageSrc?: string;
  title?: string;
}

export const PodcastBlogSplitSection = ({
  episode = "Episode 42",
  excerpt = "A conversation about emerging email trends and technologies.",
  host = "Jane Smith",
  imageAlt = "Podcast studio",
  imageSrc = "https://emailcn.vercel.app/api/email-assets/hero/mosaic-1.jpg",
  title = "The future of email",
}: Omit<PodcastBlogSplitProps, "theme">) => {
  const posts = [
    {
      episode,
      excerpt,
      host,
      imageAlt,
      imageSrc,
      title,
    },
  ];

  return (
    <>
      <BlogContent layout="podcast-split" posts={posts} />
    </>
  );
};

export const PodcastBlogSplit = ({
  theme = defaultTheme,
  episode = "Episode 42",
  excerpt = "A conversation about emerging email trends and technologies.",
  host = "Jane Smith",
  imageAlt = "Podcast studio",
  imageSrc = "https://emailcn.vercel.app/api/email-assets/hero/mosaic-1.jpg",
  title = "The future of email",
}: PodcastBlogSplitProps) => (
  <BlogEmailShell preview={title} theme={theme}>
    <PodcastBlogSplitSection
      episode={episode}
      excerpt={excerpt}
      host={host}
      imageAlt={imageAlt}
      imageSrc={imageSrc}
      title={title}
    />
  </BlogEmailShell>
);

PodcastBlogSplit.PreviewProps = {
  episode: "Episode 42",
  excerpt: "A conversation about emerging email trends and technologies.",
  host: "Jane Smith",
  imageAlt: "Podcast studio",
  imageSrc: "https://emailcn.vercel.app/api/email-assets/hero/mosaic-1.jpg",
  theme: defaultTheme,
  title: "The future of email",
} satisfies PodcastBlogSplitProps;
